import {ChangeDetectionStrategy, ChangeDetectorRef, Component, OnInit} from '@angular/core';
import {Router} from "@angular/router";

@Component({
    selector: 'app-page-not-found',
    templateUrl: './page-not-found.component.html',
    changeDetection: ChangeDetectionStrategy.OnPush,
    styleUrls: ['./page-not-found.component.css'],
    standalone: false
})
export class PageNotFoundComponent implements OnInit {
	public top : string = "0px";
	public left : string = "0px";

	constructor(public router : Router,private changeDetectorRef: ChangeDetectorRef) {
		changeDetectorRef.detach();
	}

	ngOnInit(): void {
		this.changeDetectorRef.detectChanges();
		document.addEventListener('mousemove',(event : any)=>{
			this.top = event.pageY+'px';
			this.left = event.pageX+'px';
			this.changeDetectorRef.detectChanges();
		});
	}
}
<div class="notfound"><h1>404</h1>
    <h2>Uh, Ohh</h2>
    <h3>Sorry we can't find what you are looking for 'cuz its so dark in here.</h3>
    <div id="torch" (click)="router.navigate(['/'])" [style]="{'top':top,'left':left}"></div>
</div>
